  ('1bea8ef6-c94f-41d6-a794-60a2af9ed2b8', $$Scheikunde$$, $$VWO$$, $$Cadmiumgeel$$, $$VWO Scheikunde 2022-II$$),
  ('fc8d1c80-eb00-41d5-b2af-3ccf277fa550', $$Scheikunde$$, $$VWO$$, $$Merox$$, $$VWO Scheikunde 2022-II$$),
  ('b9d9c746-8609-46d9-9138-5504426eb356', $$Scheikunde$$, $$VWO$$, $$EPDM-rubber$$, $$VWO Scheikunde 2022-II$$),
